// Functions stored in variables
const greet = (name) => `Hello, ${name}!`;

// Functions in arrays
const validators = [
  (v) => v.length >= 3,
  (v) => /^[a-z]+$/.test(v),
];

// Functions in objects
const formatters = {
  upper: (s) => s.toUpperCase(),
  lower: (s) => s.toLowerCase(),
  trim: (s) => s.trim(),
};

// Passed as arguments
[1, 2, 3].map(n => n * 2); // map takes a function argument

// A HOF that applies a function to each element and logs the result
function applyAndLog(arr, transform) {
  arr.forEach(item => {
    const result = transform(item);
    console.log(`${item} → ${result}`);
  });
}

applyAndLog([1, 2, 3], n => n * n);
// 1 → 1
// 2 → 4
// 3 → 9

applyAndLog(['hello', 'world'], s => s.toUpperCase());
// hello → HELLO
// world → WORLD

// A HOF that runs a function only if a condition is true
function when(condition, fn) {
  return (...args) => {
    if (condition) return fn(...args);
  };
}

const isAdmin = true;
const deleteUser = when(isAdmin, (id) => console.log(`Deleted user ${id}`));

deleteUser(42); // 'Deleted user 42'

// A multiplier factory
function multiplier(factor) {
  return (number) => number * factor;
}

const double = multiplier(2);
const triple = multiplier(3);
const tenTimes = multiplier(10);

double(5);    // 10
triple(5);    // 15
tenTimes(5);  // 50

// A logger factory that adds a prefix
function createLogger(prefix) {
  return (message) => console.log(`[${prefix}] ${message}`);
}

const infoLog = createLogger('INFO');
const errorLog = createLogger('ERROR');

infoLog('Server started');   // '[INFO] Server started'
errorLog('Connection lost'); // '[ERROR] Connection lost'

function TodoList({ items, onDelete, onToggle }) {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>
          {item.title}
          {/* Without HOF — must use inline arrow */}
          <button onClick={() => onDelete(item.id)}>Delete</button>

          {/* With HOF — cleaner in deeply nested JSX */}
          <button onClick={createDeleteHandler(item.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}

function createDeleteHandler(id) {
  return (event) => {
    event.preventDefault();
    onDelete(id);
  };
}

// HOC: wraps any component with a loading spinner
function withLoadingSpinner(WrappedComponent) {
  return function ComponentWithSpinner({ isLoading, ...props }) {
    if (isLoading) return <div className="spinner">Loading...</div>;
    return <WrappedComponent {...props} />;
  };
}

// Usage:
const UserListWithSpinner = withLoadingSpinner(UserList);

function App() {
  const { data, loading } = useFetchUsers();
  return <UserListWithSpinner isLoading={loading} users={data} />;
}

// A custom hook — a HOF that returns stateful values and handlers
function useCounter(initialValue = 0, step = 1) {
  const [count, setCount] = useState(initialValue);

  const increment = () => setCount(c => c + step);
  const decrement = () => setCount(c => Math.max(0, c - step));
  const reset = () => setCount(initialValue);

  return { count, increment, decrement, reset };
}

// Any component can reuse this logic:
function Counter() {
  const { count, increment, decrement, reset } = useCounter(0, 2);
  return (
    <div>
      <button onClick={decrement}>-</button>
      <span>{count}</span>
      <button onClick={increment}>+</button>
      <button onClick={reset}>Reset</button>
    </div>
  );
}

// React.memo is a HOF — takes a component, returns a memoized component
const MemoizedButton = React.memo(function Button({ label, onClick }) {
  return <button onClick={onClick}>{label}</button>;
});

// Same with arrow component:
const MemoizedCard = React.memo(({ title, content }) => (
  <div className="card">
    <h3>{title}</h3>
    <p>{content}</p>
  </div>
));

// ❌ handleClick() is called immediately — result (undefined) is passed to onClick
<button onClick={handleClick()}>Click</button>

// ✅ Pass the function reference
<button onClick={handleClick}>Click</button>

// ✅ Wrap in arrow if you need to pass arguments
<button onClick={() => handleClick(item.id)}>Click</button>

// ❌ A new handler function is created on every render for every item
function List({ items, onDelete }) {
  return items.map(item => (
    <Item
      key={item.id}
      onDelete={() => onDelete(item.id)} // new function every render
    />
  ));
}

// ✅ For performance-sensitive cases, pass the id and let the child call it
function List({ items, onDelete }) {
  return items.map(item => (
    <Item key={item.id} item={item} onDelete={onDelete} />
  ));
}
// In Item: <button onClick={() => onDelete(item.id)}>Delete</button>
